INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '7bed7e77-94fc-4203-b273-39a941481843',
  '00000000-0000-0000-0000-000000000001',
  $escape$nmap - Detecting Evil Twin and Rogue APs in WPA2 Networks$escape$,
  $escape$To scan for rogue Access Points (APs) and evil twins in WPA2 networks, use nmap's `--script` option with the `broadcast-ssid` and `wps-enum` scripts. This will broadcast a probe request to all devices on the network and attempt to enumerate WPS capabilities. Use the `--script-args` option to specify a custom probe request and WPS PIN.$escape$,
  $escape$nmap -sN -Pn --script=broadcast-ssid,wps-enum --script-args 'broadcast-ssid=<SSID>,wps-pin=<WPS_PIN>' 192.168.1.0/24$escape$,
  $escape$bash$escape$,
