INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '0d46980d-619e-4d35-ac9a-3b65963bd9cf',
  '00000000-0000-0000-0000-000000000001',
  $escape$nmap — OWASP Manual Testing vs Automated Scanning$escape$,
  $escape$When performing web application testing with nmap, consider OWASP's recommendations for manual testing. Use nmap's script engines (NSE) to identify vulnerabilities, such as SQL injection and cross-site scripting (XSS). Utilize NSE scripts like 'http-detect-proxy' to identify proxies and 'http-slowloris' to detect slowloris attacks. For automated scanning, use nmap's built-in services scanning (-sV) and OS detection (-O) options. Combine results with nmap's XML output to identify potential security issues.$escape$,
  NULL,
  NULL,
